function requiredString(value, label) {
  if (typeof value !== 'string' || !value.trim()) {
    throw new Error(`[SIGAF/PYS] ${label} requerido`);
  }
  return value.trim();
}

function optionalString(value, fallback = '') {
  return typeof value === 'string' && value.trim() ? value.trim() : fallback;
}

function stripTrailingSlash(value) {
  let out = optionalString(value);
  while (out.endsWith('/')) out = out.slice(0, -1);
  return out;
}

function callbackBase(url) {
  const suffix = '/sync/paz-y-salvo/firma-completada';
  const clean = stripTrailingSlash(url);
  return clean.endsWith(suffix) ? clean.slice(0, -suffix.length) : clean;
}

function cleanCell(value) {
  return String(value ?? '').replace(/\s+/g, ' ').trim();
}

function placeholder(name) {
  return '{' + '{' + name + '}' + '}';
}

const input = $input.first().json || {};
const body = input.body || input;
const eventType = requiredString(body.eventType, 'eventType');

if (eventType !== 'PAZ_Y_SALVO_SIGN_REQUESTED') {
  throw new Error(`[SIGAF/PYS] eventType no soportado: ${eventType}`);
}

const eventId = requiredString(body.eventId, 'eventId');
const sigafCaseId = requiredString(body.sigafCaseId, 'sigafCaseId');
const actaNumber = requiredString(body.actaNumber, 'actaNumber');
const fechaActa = optionalString(body.fechaActa, new Date().toLocaleDateString('es-CO'));
const motivo = optionalString(body.motivo, 'DESVINCULACION');
const motivoLabels = {
  DESVINCULACION: 'Desvinculacion',
  RENUNCIA: 'Renuncia',
  JUBILACION: 'Jubilacion',
  TRASLADO_EXTERNO: 'Traslado externo',
  OTRO: 'Otro',
};

const funcionarioEntrega = {
  fullName: requiredString(body.funcionarioEntrega?.fullName, 'funcionarioEntrega.fullName'),
  identificacion: requiredString(body.funcionarioEntrega?.identificacion, 'funcionarioEntrega.identificacion'),
  cargo: optionalString(body.funcionarioEntrega?.cargo),
  area: optionalString(body.funcionarioEntrega?.area),
  contractEndDate: optionalString(body.funcionarioEntrega?.contractEndDate),
};

const funcionarioRecibe = {
  fullName: optionalString(body.funcionarioRecibe?.fullName, 'RESPONSABLE ACTIVOS FIJOS'),
  email: optionalString(body.funcionarioRecibe?.email),
};

const signature = {
  signatureImageFileId: requiredString(body.signature?.signatureImageFileId, 'signature.signatureImageFileId'),
  signatureAnchor: optionalString(body.signature?.signatureAnchor, 'FIRMA RESPONSABLE ACTIVOS FIJOS'),
};

const callback = {
  url: optionalString(body.callback?.url),
  baseUrl: callbackBase(body.callback?.url),
  secret: optionalString(body.callback?.secret),
};

const itemsRaw = Array.isArray(body.items) ? body.items : [];
if (!itemsRaw.length) {
  throw new Error('[SIGAF/PYS] items debe tener al menos un activo');
}

const items = itemsRaw.map((item, index) => ({
  itemNumber: Number.isFinite(Number(item.itemNumber)) ? Number(item.itemNumber) : index + 1,
  name: requiredString(item.name, `items[${index}].name`),
  plate: optionalString(item.plate),
  estadoFisico: optionalString(item.estadoFisico, 'BUENO'),
  notes: optionalString(item.notes),
}));

const activosTabla = [
  'No.\tActivo\tPlaca\tEstado\tObservaciones',
  ...items.map((item) => [
    item.itemNumber,
    cleanCell(item.name),
    cleanCell(item.plate || 'N/A'),
    cleanCell(item.estadoFisico),
    cleanCell(item.notes || ''),
  ].join('\t')),
].join('\n');

const replacements = [
  [placeholder('CODIGO_ACTA'), actaNumber],
  [placeholder('FECHA_ACTA'), fechaActa],
  [placeholder('VERSION'), optionalString(body.version, '1.0')],
  [placeholder('MOTIVO'), motivoLabels[motivo] || motivo],
  [placeholder('FUNCIONARIO_ENTREGA_NOMBRE'), funcionarioEntrega.fullName],
  [placeholder('FUNCIONARIO_ENTREGA_IDENTIFICACION'), funcionarioEntrega.identificacion],
  [placeholder('CARGO_FUNCIONARIO'), funcionarioEntrega.cargo],
  [placeholder('AREA_ENTREGA'), funcionarioEntrega.area],
  [placeholder('FECHA_TERMINACION_CONTRATO'), funcionarioEntrega.contractEndDate],
  [placeholder('FUNCIONARIO_RECIBE_NOMBRE'), funcionarioRecibe.fullName],
  [placeholder('FUNCIONARIO_RECIBE_EMAIL'), funcionarioRecibe.email],
  [placeholder('OBSERVACIONES'), optionalString(body.observaciones)],
  [placeholder('ACTIVOS_TABLA'), activosTabla],
].map(([placeholderText, value]) => ({ placeholder: placeholderText, value: String(value ?? '') }));

return [{
  json: {
    eventType,
    eventId,
    sigafCaseId,
    actaNumber,
    fechaActa,
    motivo,
    funcionarioEntrega,
    funcionarioRecibe,
    observaciones: optionalString(body.observaciones),
    signature,
    callback,
    items,
    replacements,
    document: {
      name: `${actaNumber} - Paz y Salvo firmado`,
      pdfName: `${actaNumber} - Paz y Salvo firmado.pdf`,
      description: `SIGAF Paz y Salvo. eventId=${eventId}; sigafCaseId=${sigafCaseId}`,
    },
    receivedAt: new Date().toISOString(),
  },
}];
